// Recebe os campos enviados pelo formulario da landing page
// (renegociacaotributaria.html) e prepara o payload para o DataCrazy.

const body = $input.first().json.body || $input.first().json;

const dividaLabels = {
  'ate-100k':    'Ate R$ 100 mil',
  '100k-500k':   'De R$ 100 mil a R$ 500 mil',
  '500k-1mi':    'De R$ 500 mil a R$ 1 milhao',
  '1mi-5mi':     'De R$ 1 milhao a R$ 5 milhoes',
  '5mi-15mi':    'De R$ 5 milhoes a R$ 15 milhoes',
  '15mi-mais':   'Acima de R$ 15 milhoes',
};

const dividaCodigo = (body.divida || '').toString().trim();
const dividaLegivel = dividaLabels[dividaCodigo] || dividaCodigo || 'Nao informado';

const telefoneDigits = (body.whatsapp || '').toString().replace(/\D/g, '');
const telefoneE164 = telefoneDigits
  ? (telefoneDigits.startsWith('55') ? '+' + telefoneDigits : '+55' + telefoneDigits)
  : '';

const origem = (body.origem && body.origem.trim())
  ? body.origem.trim()
  : 'Landing Page - Renegociacao Tributaria';

const utmSource   = (body.utm_source   || '').toString().trim();
const utmCampaign = (body.utm_campaign || '').toString().trim();
const utmMedium   = (body.utm_medium   || '').toString().trim();

const anotacaoLinhas = [
  'Lead capturado pelo formulario da landing page.',
  '',
  'Valor da divida tributaria: ' + dividaLegivel,
  'Segmento da empresa: ' + (body.segmento || 'Nao informado'),
  '',
  'Origem: ' + origem,
  'UTM Source: '   + (utmSource   || '-'),
  'UTM Campaign: ' + (utmCampaign || '-'),
  'UTM Medium: '   + (utmMedium   || '-'),
  '',
  'Capturado em: ' + (body.timestamp || new Date().toISOString()),
  'User-Agent: '   + (body.user_agent || '-'),
];

return [{
  json: {
    name:    (body.nome    || '').toString().trim(),
    email:   (body.email   || '').toString().trim(),
    phone:   telefoneE164 || (body.whatsapp || '').toString().trim(),
    company: (body.empresa || '').toString().trim(),
    source:  origem,
    dividaCodigo,
    dividaLegivel,
    segmento: (body.segmento || '').toString().trim(),
    utmSource,
    utmCampaign,
    utmMedium,
    anotacao: anotacaoLinhas.join('\n'),
    capturadoEm: body.timestamp || new Date().toISOString(),
  },
}];
